diff --git a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
index 15e798bd6c98..e450065d089e 100644
--- a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
+++ b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
@@ -15716,7 +15716,42 @@ BoUpSLP::vectorizeTree(const ExtraValueToDebugLocsMap &ExternallyUsedValues,
   // cache correctness.
   // NOTE: removeInstructionAndOperands only marks the instruction for deletion
   // - instructions are not deleted until later.
-  removeInstructionsAndOperands(ArrayRef(RemovedInsts));
+  // Filter out instructions that still have live users outside of the deletion
+  // set and not explicitly ignored. This satisfies the invariant expected by
+  // removeInstructionsAndOperands. Do this filtering only for horizontal
+  // reductions (when UserIgnoreList is set) to avoid perturbing general SLP
+  // behavior and test expectations.
+  if (UserIgnoreList) {
+    // For horizontal reductions, only mark instructions for deletion if all
+    // their users are already marked deleted by this point or are part of the
+    // same deletion set. This satisfies removeInstructionsAndOperands
+    // invariants.
+    SmallVector<Instruction *, 16> FilteredRemovedInsts;
+    FilteredRemovedInsts.reserve(RemovedInsts.size());
+    for (Instruction *I : RemovedInsts) {
+      if (I->use_empty()) {
+        FilteredRemovedInsts.push_back(I);
+        continue;
+      }
+      bool SafeToDelete = true;
+      for (Use &U : I->uses()) {
+        Value *Usr = U.getUser();
+        auto *UsrI = dyn_cast<Instruction>(Usr);
+        if (!UsrI) { SafeToDelete = false; break; }
+        // User must be either already marked deleted (by previously inserted
+        // DeletedInstructions entries) or included in the current deletion set.
+        if (!isDeleted(UsrI) && !is_contained(RemovedInsts, UsrI)) {
+          SafeToDelete = false;
+          break;
+        }
+      }
+      if (SafeToDelete)
+        FilteredRemovedInsts.push_back(I);
+    }
+    removeInstructionsAndOperands(ArrayRef(FilteredRemovedInsts));
+  } else {
+    removeInstructionsAndOperands(ArrayRef(RemovedInsts));
+  }

   Builder.ClearInsertionPoint();
   InstrElementSize.clear();

